import { Component, EventEmitter, input } from '@angular/core';

@Component({
  templateUrl: './icon-button.html',
  selector: 'icon-button',
  styleUrl: 'icon-button.css',
})
export class IconButton {
  colorMap = {
    delete: '#ef9c9c',
    settings: 'lightgray',
    calendar_month: 'lightblue',
    add: 'blue',
    arrow_back_2: 'white',
    play_arrow: 'white',
    edit: 'yellow',
    move_item: 'white',
  };
  onClick = new EventEmitter<Event>();
  size = input<'small' | 'large'>('small');
  style = input<Record<string, string>>();
  icon = input<
    | 'add'
    | 'arrow_back_2'
    | 'calendar_month'
    | 'delete'
    | 'edit'
    | 'move_item'
    | 'play_arrow'
    | 'settings'
  >();
}

import { Component, computed, inject, resource } from '@angular/core';
import { toSignal } from '@angular/core/rxjs-interop';
import { ActivatedRoute } from '@angular/router';
import { DBService } from '../services/DBService';
import { TodoItem } from '../components/todo-item/todo-item';
import { IconButton } from '../components/icon-button/icon-button';
@Component({
  selector: 'list-page',
  templateUrl: './list-page.html',
  imports: [TodoItem, IconButton],
})
export class ListPage {
  addItem() {
    console.log('adding item');
    this.dbService.addItem();
  }

  private route = inject(ActivatedRoute);
  private data = toSignal(this.route.data);
  dbService = inject(DBService);
  date = computed(() => (this.data() ? this.data()!['date'] : '12'));

  dbResource = resource({
    params: () => ({ date: this.date() }),
    loader: (params) => this.dbService.getItemsByDate(params.params.date),
  });

  isLoading = computed(() => this.dbResource.status() === 'loading');
  isError = computed(() => this.dbResource.status() === 'error');
}

